#include<bits/stdc++.h>
using namespace std;
string a;
int ans=0;
int ans2=0;
int main(){
    while(1){
        char c;
        cin>>c;
        a+=c;
        if(c=='E') break;

    }
    for(int i=0;i<a.size();i++){
        if(ans>=11&&ans-ans2>1){
            cout<<ans<<":"<<ans2<<"\n";
            ans=0;
            ans2=0;
        }else if(ans2>=11&&ans2-ans>1){
            cout<<ans<<":"<<ans2<<"\n";
            ans2=0;
            ans=0;
        }
        if(a[i]=='W'){
            ans++;
        }else if(a[i]=='L'){
            ans2++;
        }

    }
    cout<<ans<<":"<<ans2<<"\n\n";
    ans=0;
    ans2=0;
    for(int i=0;i<a.size();i++){
        if(ans>=21&&ans-ans2>1){
            cout<<ans<<":"<<ans2<<"\n";
            ans=0;
            ans2=0;
        }else if(ans2>=21&&ans2-ans>1){
            cout<<ans<<":"<<ans2<<"\n";
            ans2=0;
            ans=0;
        }
        if(a[i]=='W'){
            ans++;
        }else if(a[i]=='L'){
            ans2++;
        }

    }
    cout<<ans<<":"<<ans2;
    return 0;
}
